module Shared.Lead

type LeadPriority = Low | Medium | High

record Empty = {}

record LeadIntake = {
  company : Str,
  priority : LeadPriority
}

record LeadSummary = {
  company : Str,
  priorityLabel : Str,
  status : Str
}

record LeadPlaybookLookup = {
  status : Str
}

record LeadPlaybook = {
  guidance : Str
}

record LeadFollowUpState = {
  summary : LeadSummary
}

module Main

import Shared.Lead

policy LeadOps = public permits {
  process "node"
}

toolserver LeadTools = "mcp" "stdio://lead-tools" with LeadOps

tool lookupLeadPlaybook = LeadTools "lookup_lead_playbook" LeadPlaybookLookup -> LeadPlaybook

priorityLabel : LeadPriority -> Str
priorityLabel priority = match priority {
  Low -> "low",
  Medium -> "medium",
  High -> "high"
}

summarizeLead : LeadIntake -> LeadSummary
summarizeLead intake = LeadSummary {
  company = intake.company,
  priorityLabel = priorityLabel intake.priority,
  status = "new"
}

playbookRequest : LeadSummary -> LeadPlaybookLookup
playbookRequest summary = LeadPlaybookLookup {
  status = summary.status
}

workflow LeadFollowUpFlow = { state : LeadFollowUpState }

summarizeLeadRoute : LeadIntake -> LeadSummary
summarizeLeadRoute intake = summarizeLead intake

route summarizeLeadApi = POST "/api/lead/summary" LeadIntake -> LeadSummary summarizeLeadRoute

main : Str
main = (playbookRequest (summarizeLead (LeadIntake { company = "Northwind", priority = High }))).status

module Main

import Shared.Lead

policy LeadOps = public permits {
  process "node"
}

toolserver LeadTools = "mcp" "stdio://lead-tools" with LeadOps

tool lookupLeadPlaybook = LeadTools "lookup_lead_playbook" LeadPlaybookLookup -> LeadPlaybook

priorityLabel : LeadPriority -> Str
priorityLabel priority = match priority {
  Low -> "low",
  Medium -> "medium",
  High -> "high"
}

summarizeLead : LeadIntake -> LeadSummary
summarizeLead : LeadIntake -> LeadDigest
summarizeLead intake = LeadDigest {
  company = intake.company,
  priorityLabel = priorityLabel intake.priority,
  owner = match intake.priority {
    High -> "senior-ae",
    _ -> "ae"
  },
  needsFollowUp = intake.priority == High
}

playbookRequest : LeadDigest -> LeadPlaybookLookup
playbookRequest digest = LeadPlaybookLookup {
  owner = digest.owner,
  needsFollowUp = digest.needsFollowUp
}

workflow LeadFollowUpFlow = { state : LeadFollowUpState }

summarizeLeadRoute : LeadIntake -> LeadDigest
summarizeLeadRoute intake = summarizeLead intake

route summarizeLeadApi = POST "/api/lead/summary" LeadIntake -> LeadDigest summarizeLeadRoute

main : Str
main = (playbookRequest (summarizeLead (LeadIntake { company = "Northwind", priority = High }))).owner

module Shared.Lead

type LeadPriority = Low | Medium | High

record Empty = {}

record LeadIntake = {
  company : Str,
  priority : LeadPriority
}

public contract LeadDigest = {
  company : Str,
  priorityLabel : Str,
  owner : Str,
  needsFollowUp : Bool
}

record LeadPlaybookLookup = {
  owner : Str,
  needsFollowUp : Bool
}

record LeadPlaybook = {
  guidance : Str
}

record LeadFollowUpState = {
  digest : LeadDigest
}
